import React, { useState } from 'react';


export default function GameBord() {
    const [dec, setDec] = useState({})
    const [playerDec, setPlayerDec] = useState({})
    const [computerDec, setComputerDec] = useState({})
    const totalCards = 52
    const copyFromEatchCard = 4

    let createDec = () => {
        let mainDec = []
        for (let i = 1; i <= totalCards /copyFromEatchCard; i++) {
            for (let x = 0; x <= copyFromEatchCard; x++) {
                mainDec.push(i)

            }
        }
        setDec(mainDec)
        giveCards()
    }
    let giveCards =async () => {
        let pDec = []
        let cDec = []
        console.log(dec.length)

        let decHolder = dec
        console.log(decHolder.length)
        while (decHolder.length > 0) {
            pDec.push(await decHolder.splice( Math.floor(Math.random() * decHolder.length),1))
            cDec.push(await decHolder.splice(Math.floor(Math.random() * decHolder.length),1))
        }
        setPlayerDec(pDec)
        setComputerDec(cDec)
        console.log(dec.length)
        console.log("p" + playerDec.length+playerDec)
        console.log("c" +computerDec.length+computerDec)


    }




    return (
        <div>
            <button onClick={() => createDec()}></button>
            <h1>hettt</h1>
        </div>
    )
}
